import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    # {Select the next node by prioritizing nodes with the lowest ratio of immediate travel cost to a heuristic factor involving the maximum variance in distances to all unvisited nodes.}

    min_combined_metric = float('inf')
    next_node = None

    for node in unvisited_nodes:
        immediate_distance = distance_matrix[current_node, node]
        variance_distances = np.var([distance_matrix[node, other_node] for other_node in unvisited_nodes if other_node != node])

        if variance_distances != 0:
            combined_metric = immediate_distance / variance_distances
        else:
            combined_metric = immediate_distance

        if combined_metric < min_combined_metric:
            min_combined_metric = combined_metric
            next_node = node

    return next_node
